import novamind_api as nm
import json

# Get group insights for S1, S2, S3, and enterprise groups
for gid in ['S1', 'S2', 'S3', 'E1', 'E2', 'E3', 'D_E09']:
    insights = nm.market.get_group_insights(group_id=gid)
    print(f'=== {gid} Insights ===')
    # Print key fields
    if isinstance(insights, dict):
        for k, v in insights.items():
            if k in ['quality_expectations', 'market_cap', 'current_subscribers', 'q_min', 'ad_effectiveness', 'referral_rates', 'reputation_influence']:
                print(f'  {k}: {json.dumps(v, default=str)[:300]}')
        # Also print any quality-related fields
        for k, v in insights.items():
            if 'quality' in k.lower() or 'expect' in k.lower():
                print(f'  {k}: {v}')
    print()
"

