./novamind-operation python-c "
import novamind_api as nm
from novamind_api import marketing, market, analytics

# Get market overview for q_min estimates
overview = market.get_market_overview()
print('=== Market Overview ===')
for k, v in overview.items():
    if isinstance(v, dict):
        print(f'{k}:')
        for k2, v2 in v.items():
            print(f'  {k2}: {v2}')
    elif isinstance(v, list):
        print(f'{k} (first 3): {v[:3]}')
    else:
        print(f'{k}: {v}')

# Get group insights
for gid in ['S1', 'S2', 'S3', 'D_E09', 'E1', 'E2', 'E3']:
    try:
        insights = market.get_group_insights(group_id=gid)
        print(f'\n=== {gid} Insights ===')
        for k, v in insights.items():
            if isinstance(v, (int, float, str)):
                print(f'  {k}: {v}')
            elif isinstance(v, dict):
                print(f'  {k}:')
                for k2, v2 in v.items():
                    print(f'    {k2}: {v2}')
    except Exception as e:
        print(f'\n{gid}: Error - {e}')
"

