import novamind_api as nm

# Check all current settings by examining recent actions
print('=== Subscriber Plan Distribution ===')
r = nm.query('SELECT c.group_id, s.plan, s.listed_price, s.effective_price, s.promotion, COUNT(*) as n, AVG(s.effective_price) as avg_ep FROM subscriptions s JOIN customers c ON s.customer_id = c.customer_id WHERE s.status=\"subscribed\" GROUP BY c.group_id, s.plan ORDER BY c.group_id, s.plan')
for row in r['rows']:
    print(f'{row[\"group_id\"]} Plan {row[\"plan\"]}: listed={row[\"listed_price\"]}, eff={row[\"effective_price\"]}, promo={row[\"promotion\"]}, n={row[\"n\"]}, avg_ep=\${row[\"avg_ep\"]:.2f}')

# Check market caps
print('\n=== Group Insights for S1 ===')
try:
    insights = nm.market.get_group_insights(group_id='S1')
    for k,v in insights.items():
        if not isinstance(v, list):
            print(f'{k}: {v}')
        elif k == 'referral_rates' or k == 'reputation_influence':
            if isinstance(v, list) and len(v) <= 10:
                for item in v:
                    print(f'  {item}')
            else:
                print(f'{k}: {len(v)} items')
except Exception as e:
    print(f'Error: {e}')

print('\n=== Group Insights for D_E09 ===')
try:
    insights = nm.market.get_group_insights(group_id='D_E09')
    for k,v in insights.items():
        if not isinstance(v, list):
            print(f'{k}: {v}')
        elif isinstance(v, list) and len(v) <= 10:
            for item in v:
                print(f'  {item}')
except Exception as e:
    print(f'Error: {e}')

# Check current enterprise threads
print('\n=== Enterprise Threads ===')
r = nm.query('SELECT * FROM enterprise_turns LIMIT 10')
for row in r['rows']:
    print(row)
"

